using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for edge/boundary cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalBoundaryData))]
    public void CalculateTotal_BoundaryCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)>
        CalculateTotalBoundaryData =>
    [
        (0.01m, 1, 0m, 0.01m),       // Minimum meaningful price
        (9999.99m, 100, 1m, 1999998m), // Large order, max tax rate
        (1m, 1, 0m, 1m),              // Tax rate at lower bound
        (1m, 1, 1m, 2m),              // Tax rate at upper bound
    ];

    // --- CalculateTotal: exception cases with DataRow ---

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativePrice_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above one")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // --- ApplyDiscount: DataRow for common discount scenarios ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(49.99, 50.0, 24.995, DisplayName = "50% off odd price")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for precision-sensitive cases ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountPrecisionData))]
    public void ApplyDiscount_PrecisionCases_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)>
        ApplyDiscountPrecisionData =>
    [
        (0.01m, 50m, 0.005m),          // Sub-cent result
        (1000000m, 0.01m, 999900m),    // Tiny discount on large amount
        (33.33m, 33.33m, 22.2211m),    // Repeating decimals (33.33 * 0.6667)
    ];

    // --- ApplyDiscount: invalid discount percentages ---

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below zero")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    [DataRow(-50.0, DisplayName = "Large negative discount")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }
}

